const now = new Date().toISOString().split('T')[0];
const anthropicStatus = $input.all()[0]?.json?.status?.description || 'Operational';
const openaiStatus = $input.all()[1]?.json?.status?.description || 'Operational';
const rss = $input.all()[2]?.json?.data || '';

const services = [
  { name: 'Claude (Anthropic)', model: 'claude-opus-4-6 / sonnet / haiku', status: anthropicStatus, paid: 'Yes' },
  { name: 'ChatGPT (OpenAI)', model: 'gpt-4o / o1 / o3 / o4-mini', status: openaiStatus, paid: 'Yes' },
  { name: 'Grok (xAI)', model: 'grok-3 / grok-3-mini', status: 'Operational', paid: 'Yes' },
  { name: 'Gemini (Google)', model: 'gemini-2.0-flash / pro', status: 'Operational', paid: 'Free+Paid' },
  { name: 'Llama (Meta)', model: 'llama-4 / llama-3.3', status: 'Operational', paid: 'Free/Open' },
  { name: 'Mistral', model: 'mistral-large-2 / small-3', status: 'Operational', paid: 'Free+Paid' },
  { name: 'Perplexity', model: 'sonar-pro / sonar', status: 'Operational', paid: 'Yes' },
  { name: 'Cohere', model: 'command-r-plus / command-a', status: 'Operational', paid: 'Yes' },
  { name: 'ElevenLabs', model: 'eleven-multilingual-v3', status: 'Operational', paid: 'Yes' },
  { name: 'Runway', model: 'gen-4 / gen-3', status: 'Operational', paid: 'Yes' },
  { name: 'Ollama (Local)', model: 'gemma4:e4b', status: 'Operational', paid: 'Free' }
];

const newModels = ['GPT-5','Claude 5','Gemini 3','Grok 4','Llama 5'].filter(m => rss.toLowerCase().includes(m.toLowerCase()));

const tableRows = services.map(s => {
  const ok = (s.status === 'Operational' || s.status === 'All Systems Operational') ? 'OK' : 'WARN';
  return '| ' + ok + ' | ' + s.name + ' | ' + s.model + ' | ' + s.paid + ' |';
}).join('
');

const alertSection = newModels.length > 0 ? '## NEW AI DETECTED
' + newModels.map(m => '- ' + m).join('
') + '

' : '';

const report = '# AI Daily Report - ' + now + '

' + alertSection + '## Services (' + services.length + ' monitored)

| Status | Service | Models | Paid |
|--------|---------|--------|------|
' + tableRows + '

*Auto-generated by Grandfathers Axe n8n workflow*
';

const telegram = newModels.length > 0
  ? 'GA ALERT: New AI detected: ' + newModels.join(', ') + '. Report saved to Obsidian.'
  : 'GA Daily: ' + services.length + ' AI services checked. All operational. Report saved.';

return [{ json: { report, date: now, filename: 'AI_Daily_Report_' + now + '.md', telegram } }];
